const webhook = $('Mken Webhook').first().json;
const tenantSlug = (webhook.query && webhook.query.tenant) ? String(webhook.query.tenant).trim() : '';

if (!tenantSlug) {
  return [{ json: { ok: false, error: 'Missing tenant query parameter', statusCode: 400 } }];
}

const tenantRow = $input.first().json;
if (!tenantRow || !tenantRow.config_data) {
  return [{ json: { ok: false, error: 'Tenant not found: ' + tenantSlug, statusCode: 404 } }];
}

const wa = tenantRow.config_data.whatsappApi || {};
const headers = webhook.headers || {};
const auth = String(headers.authorization || headers.Authorization || '').trim();
const expected = 'Bearer ' + String(wa.token || '').trim();

if (!wa.token || auth !== expected) {
  return [{ json: { ok: false, error: 'Unauthorized', statusCode: 401 } }];
}

const payload = webhook.body && typeof webhook.body === 'object' ? webhook.body : webhook;
const to = payload.to;
const message = payload.body;
const event = payload.event || null;
const appointment = payload.appointment || null;

if (!to || !message) {
  return [{ json: { ok: false, error: 'Missing to or body', statusCode: 400 } }];
}

const gw = wa.gateway || {};
const sendProvider = gw.provider || (wa.provider !== 'custom' ? wa.provider : null);

if (!sendProvider || sendProvider === 'none' || sendProvider === 'custom') {
  return [{ json: { ok: false, error: 'Gateway provider not configured for tenant', statusCode: 422 } }];
}

const send = {
  provider: sendProvider,
  instanceId: gw.instanceId || wa.instanceId || '',
  accountSid: gw.accountSid || wa.accountSid || '',
  phoneNumberId: gw.phoneNumberId || wa.phoneNumberId || '',
  token: gw.token || (wa.provider !== 'custom' ? wa.token : ''),
  fromNumber: gw.fromNumber || wa.fromNumber || '',
  templateName: gw.templateName || wa.templateName || '',
  languageCode: gw.languageCode || wa.languageCode || 'ar'
};

if (sendProvider === 'ultramsg' && (!send.instanceId || !send.token)) {
  return [{ json: { ok: false, error: 'UltraMsg credentials missing in tenant config', statusCode: 422 } }];
}
if (sendProvider === 'twilio' && (!send.accountSid || !send.token || !send.fromNumber)) {
  return [{ json: { ok: false, error: 'Twilio credentials missing in tenant config', statusCode: 422 } }];
}

return [{ json: { ok: true, to, message, event, appointment, send, tenant: tenantSlug, statusCode: 200 } }];

const item = $input.first().json;
const send = item.send;
const phone = String(item.to || '').replace(/\D/g, '');
const auth = Buffer.from(send.accountSid + ':' + send.token).toString('base64');

const params = new URLSearchParams();
params.append('To', 'whatsapp:+' + phone);
params.append('From', 'whatsapp:' + String(send.fromNumber).replace(/^\+?/, '+'));
params.append('Body', item.message);

const res = await fetch('https://api.twilio.com/2010-04-01/Accounts/' + send.accountSid + '/Messages.json', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    'Authorization': 'Basic ' + auth
  },
  body: params.toString()
});

if (!res.ok) {
  const text = await res.text();
  throw new Error('Twilio failed: ' + res.status + ' ' + text.slice(0, 200));
}

return [{ json: { ok: true, provider: 'twilio', tenant: item.tenant, to: item.to, event: item.event } }];
